const allRows = $input.all();
const triggerData = $('New Record Created').item.json;
const currentPhoneNumber = String(triggerData.phoneNumber || '');

const matchCount = allRows.filter(item => String(item.json.phoneNumber || '') === currentPhoneNumber).length;
const isDuplicate = matchCount > 1;

// Convert timestamp to ISO 8601 date format (YYYY-MM-DD)
const rawTimestamp = triggerData.timestamp || '';
let dateOnly = '';
if (rawTimestamp) {
  // Extract just the date part (YYYY-MM-DD)
  const parts = rawTimestamp.match(/^(\d{4}-\d{2}-\d{2})/);
  if (parts) {
    dateOnly = parts[1];
  }
}

return [{
  json: {
    isDuplicate,
    placeName: triggerData.placeName || '',
    placeId: triggerData.placeId || '',
    phoneNumber: currentPhoneNumber,
    email: (triggerData.email || '').trim(),
    instagramHandle: triggerData.instagramHandle || '',
    overallScore: triggerData.overallScore || '',
    role: triggerData.role || '',
    country: triggerData.country || '',
    website: triggerData.website || '',
    cuisine: triggerData.cuisine || '',
    signatureDishes: triggerData.signatureDishes || '',
    timestamp: dateOnly,
    pdfLink: triggerData.pdfLink || ''
  }
}];

