const deduplicateData = $('Deduplicate Check').item.json;
const website = deduplicateData.website || '';
const email = deduplicateData.email || '';
const instagramHandle = deduplicateData.instagramHandle || '';
const placeId = deduplicateData.placeId || '';
const placeName = deduplicateData.placeName || '';

function extractDomain(url) {
  if (!url) return '';
  try {
    let domain = url.replace(/^https?:\/\//, '').replace(/^www\./, '');
    domain = domain.split('/')[0].toLowerCase().trim();
    return domain;
  } catch (e) { return ''; }
}

function extractEmailDomain(email) {
  if (!email || !email.includes('@')) return '';
  return email.split('@')[1].toLowerCase().trim();
}

// Invalid/placeholder inputs users commonly type
const invalidInputs = ['none', 'n/a', 'na', 'nil', 'null', '-', '--', 'no', 'no website', 'nowebsite', 'tbc', 'tbd', 'unknown', 'test', '.', '..'];

function isInvalidInput(value) {
  if (!value) return true;
  const cleaned = value.toLowerCase().trim();
  return invalidInputs.includes(cleaned);
}

// Validate domain format (must have at least one dot and valid chars)
function isValidDomain(domain) {
  if (!domain || domain.length < 4) return false; // minimum: a.co
  if (!domain.includes('.')) return false;
  // Basic domain pattern: alphanumeric, hyphens, dots
  const domainPattern = /^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)+$/i;
  return domainPattern.test(domain);
}

// Website domain blacklist (social/booking platforms)
const websiteBlacklist = ['facebook.com', 'm.facebook.com', 'instagram.com', 'tiktok.com', 'foodpanda.sg', 'quandoo.com',
  'foodpanda.com', 'grab.com', 'sevenrooms.com', 'linktr.ee', 'wa.link', 'getz.co', 'bit.ly', 'google.com', 'canva.com', 'canva.site', 'inline.app', 'oddle.me', 'ichefpos.com', 'lin.ee', 'line.me', 'order.nidin.shop', 'jotform.com'];

// Email domain blacklist (social/booking + B2C email providers)
const emailBlacklist = [
  'facebook.com', 'instagram.com',
  'gmail.com', 'yahoo.com', 'outlook.com', 'hotmail.com', 'live.com', 'msn.com',
  'icloud.com', 'me.com', 'mac.com', 'aol.com', 'protonmail.com', 'proton.me',
  'ymail.com', 'rocketmail.com', 'mail.com', 'zoho.com', 'gmx.com', 'gmx.net'
];

function isWebsiteBlacklisted(domain) {
  if (!domain) return true;
  return websiteBlacklist.some(bl => domain === bl || domain.endsWith('.' + bl));
}

function isEmailBlacklisted(domain) {
  if (!domain) return true;
  return emailBlacklist.some(bl => domain === bl || domain.endsWith('.' + bl));
}

// Check for invalid input first, then extract and validate
const websiteDomain = isInvalidInput(website) ? '' : extractDomain(website);
const emailDomain = isInvalidInput(email) ? '' : extractEmailDomain(email);

// Final validation: must be valid format AND not blacklisted
const validWebsiteDomain = (isValidDomain(websiteDomain) && !isWebsiteBlacklisted(websiteDomain)) ? websiteDomain : '';
const validEmailDomain = (isValidDomain(emailDomain) && !isEmailBlacklisted(emailDomain)) ? emailDomain : '';

const personRecordId = $json.personRecordId || '';

return [{
  json: {
    websiteDomain: validWebsiteDomain,
    emailDomain: validEmailDomain,
    instagramHandle: instagramHandle.replace('@', ''),
    placeId,
    placeName,
    country: deduplicateData.country || '',
    cuisine: deduplicateData.cuisine || '',
    personRecordId
  }
}];

// Extract company record ID and prepare data
const searchResult = $input.first().json;
const preparedData = $('Prepare Company Search').first().json;

let companyRecordId = '';
let foundByMethod = null;
let needsInstagramUpdate = false;

if (searchResult.data && searchResult.data.length > 0) {
  companyRecordId = searchResult.data[0].id.record_id;
  const company = searchResult.data[0];

  // Helper function to get value from Attio's array format
  function getAttioValue(fieldArray, subfield = 'value') {
    if (!fieldArray || fieldArray.length === 0) return null;
    return fieldArray[0][subfield];
  }

  // Infer which method found it by checking what matched
  // Priority order: websiteDomain, emailDomain, instagram, placeId, placeName

  // Check domains (special case - array of domain objects)
  if (preparedData.websiteDomain && company.values.domains && company.values.domains.length > 0) {
    const companyDomains = company.values.domains.map(d => d.domain || '').join(',').toLowerCase();
    if (companyDomains.includes(preparedData.websiteDomain.toLowerCase())) {
      foundByMethod = 'websiteDomain';
    }
  }

  if (!foundByMethod && preparedData.emailDomain && company.values.domains && company.values.domains.length > 0) {
    const companyDomains = company.values.domains.map(d => d.domain || '').join(',').toLowerCase();
    if (companyDomains.includes(preparedData.emailDomain.toLowerCase())) {
      foundByMethod = 'emailDomain';
    }
  }

  // Check Instagram
  if (!foundByMethod && preparedData.instagramHandle) {
    const companyInstagram = getAttioValue(company.values.instagram);
    if (companyInstagram && companyInstagram.toLowerCase() === preparedData.instagramHandle.toLowerCase()) {
      foundByMethod = 'instagram';
    }
  }

  // Check Place ID
  if (!foundByMethod && preparedData.placeId) {
    const companyPlaceId = getAttioValue(company.values.place_id);
    if (companyPlaceId && companyPlaceId === preparedData.placeId) {
      foundByMethod = 'placeId';
    }
  }

  // Check Name
  if (!foundByMethod && preparedData.placeName) {
    const companyName = getAttioValue(company.values.name);
    if (companyName && companyName.toLowerCase() === preparedData.placeName.toLowerCase()) {
      foundByMethod = 'placeName';
    }
  }

  // Fallback if we couldn't determine the method
  if (!foundByMethod) foundByMethod = 'unknown';

  // Check if Instagram needs updating
  const companyInstagram = getAttioValue(company.values.instagram);
  needsInstagramUpdate = foundByMethod !== 'instagram' && preparedData.instagramHandle && !companyInstagram;
}

return [{
  json: {
    companyRecordId,
    foundByMethod,
    needsInstagramUpdate,
    ...preparedData
  }
}];

